import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as s,o as t,c as e,b as p,e as c}from"./app-aebb41cf.js";const l={},o=c(`<h1 id="html-大揭秘" tabindex="-1"><a class="header-anchor" href="#html-大揭秘" aria-hidden="true">#</a> HTML 大揭秘</h1><div class="hint-container info"><p class="hint-container-title">共勉</p><p>不要哀求，学会争取。若是如此，终有所获。</p></div><div class="hint-container tip"><p class="hint-container-title">原文</p></div><h2 id="一、前言" tabindex="-1"><a class="header-anchor" href="#一、前言" aria-hidden="true">#</a> 一、前言</h2><p>准备工作完成，就该正式进入 <code>Web</code> 前端相关知识的学习了。而前端三件套（<code>HTML</code>、<code>CSS</code>、<code>JavaScript</code>）中，首当其冲的当然就是 <code>HTML</code> 。本篇文章中，就来看看 <code>HTML</code> 的基础语法学习。</p><h2 id="二、概念" tabindex="-1"><a class="header-anchor" href="#二、概念" aria-hidden="true">#</a> 二、概念</h2><p><code>HTML</code>（<code>Hyper Text Markup Language</code>），中文译为超文本标记语言。其中，我们需要注意两个关键词。一个是 <strong>超文本</strong>，一个是 <strong>标记</strong>。所谓超文本，就是将不同空间的文字信息通过超链接的方式组织在一起的网状文本，往简单了将就是我们说的链接。而标记的另一个名字也叫标签，就是网页源码中带尖括号（<code>&lt;&gt;</code>）的文本。</p><h2 id="三、语法" tabindex="-1"><a class="header-anchor" href="#三、语法" aria-hidden="true">#</a> 三、语法</h2><h3 id="_1-标签" tabindex="-1"><a class="header-anchor" href="#_1-标签" aria-hidden="true">#</a> 1. 标签</h3><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>
    程序猿村雨遥
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以上就是一个标签示例，其中 <code>&lt;h1&gt;</code> 叫做 <strong>开始标签</strong>，而 <code>&lt;/h1&gt;</code> 叫做 <strong>结束标签</strong>。</p><p>通过观察，可以发现标签的主要特点，分别是：</p><ul><li>标签成对出现，标签中间包裹内容。</li><li>标签由尖括号（<code>&lt;&gt;</code>）中加英文单词共同组成，而这个英文单词，就叫做标签名。</li><li>相比于开始标签，结束标签多了 <code>/</code></li></ul><p>此外，标签还有不同的分类，一类是单标签，而另一类则是双标签。</p><p>单标签指的是那些只有开始标签，没有结束标签的标签，而双标签则是那些成对出现的标签。</p><h3 id="_2-html-基本骨架" tabindex="-1"><a class="header-anchor" href="#_2-html-基本骨架" aria-hidden="true">#</a> 2. HTML 基本骨架</h3><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>head</span><span class="token punctuation">&gt;</span></span>
        网页头部
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>head</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span>
        网页主题内容
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>以上就是 <code>HTML</code> 的基本骨架，网页所有内容都包含在 <code>html</code> 标签中。网页中，主要由头部 <code>head</code> 和主体 <code>body</code> 共同组成。其中头部用于存放给浏览器使用的信息，比如 <code>CSS</code> 样式、<code>JS</code> 脚本。而网页主体则存放展示给用户的信息，如图片、文字、视频等。</p><h3 id="_3-标签之间的关系" tabindex="-1"><a class="header-anchor" href="#_3-标签之间的关系" aria-hidden="true">#</a> 3. 标签之间的关系</h3><p>各标签之间，最主要的有两种关系，一种是 <strong>嵌套关系</strong>，一种是 <strong>并列关系</strong>，而它们存在的意义就是让我们明确标签的书写位置，让代码格式更加整齐，提高代码可读性。</p><p>以基本骨架中的代码来说，<code>html</code> 和 <code>head</code> 是嵌套关系，而 <code>head</code> 和 <code>body</code> 之间的关系则是并列关系。</p><ul><li><strong>嵌套关系</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>html</span><span class="token punctuation">&gt;</span></span>
    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>head</span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>head</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>html</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>并列关系</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>head</span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>head</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>body</span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>body</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_4-注释" tabindex="-1"><a class="header-anchor" href="#_4-注释" aria-hidden="true">#</a> 4. 注释</h3><p>注释就是对代码的解释说明，存在的意义是让开发者能更加轻松地了解代码。一般是开发者在编码时为某些语句、程序段、函数等添加的提示，从而提高代码的可读性，方便其他开发者快速掌握，也方便后续代码修改。</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token comment">&lt;!-- 注释内容 --&gt;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_5-标题" tabindex="-1"><a class="header-anchor" href="#_5-标题" aria-hidden="true">#</a> 5. 标题</h3><p>一般用在文章标题、网页区域名称、产品名称等，共分为 6 级标题，对应的标签分别是：</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span>一级标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h2</span><span class="token punctuation">&gt;</span></span>二级标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h2</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h3</span><span class="token punctuation">&gt;</span></span>三级标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h3</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h4</span><span class="token punctuation">&gt;</span></span>四级标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h4</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h5</span><span class="token punctuation">&gt;</span></span>五级标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h5</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h6</span><span class="token punctuation">&gt;</span></span>六级标题<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h6</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在日常使用时需要注意，一个网页中 <code>h1</code> 一般只能使用一次，而 <code>h2~h6</code> 则没有使用次数的限制。</p><h3 id="_6-段落" tabindex="-1"><a class="header-anchor" href="#_6-段落" aria-hidden="true">#</a> 6. 段落</h3><p>一般用于文章段落、产品描述信息等。该标签会自动在其前后创建一些空白，浏览器将自动添加这些空间。</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_7-换行-水平线" tabindex="-1"><a class="header-anchor" href="#_7-换行-水平线" aria-hidden="true">#</a> 7. 换行 &amp; 水平线</h3><ul><li><strong>换行</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>br</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><ul><li><strong>水平线</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>hr</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>不同于其他双标签，这两个标签都属于单标签，用于实现文本换行和在文本中间添加水平线。</p><h3 id="_8-文本格式化" tabindex="-1"><a class="header-anchor" href="#_8-文本格式化" aria-hidden="true">#</a> 8. 文本格式化</h3><p>可以给文本添加特殊格式，比如加粗、斜体、下划线、删除线等效果。</p><ul><li><strong>加粗</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>b</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>b</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>strong</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>strong</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>斜体</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>i</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>i</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>em</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>em</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>下划线</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>u</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>u</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ins</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>ins</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>删除线</strong></li></ul><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>s</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>s</span><span class="token punctuation">&gt;</span></span>
<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>del</span><span class="token punctuation">&gt;</span></span>村雨遥<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>del</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="_9-图片" tabindex="-1"><a class="header-anchor" href="#_9-图片" aria-hidden="true">#</a> 9. 图片</h3><p>为了在网页中插入图片，可以使用图像标签，其使用语法如下：</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>img</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>图片地址<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>其中，<code>src</code> 属性用于指定图片位置和名称，是 <code>img</code> 标签不可缺少的属性。</p><p>除开 <code>src</code> 属性之外， <code>img</code> 最常用的标签还有下表中的几个。</p><table><thead><tr><th>属性</th><th>作用</th><th>说明</th></tr></thead><tbody><tr><td><code>alt</code></td><td>替换文本</td><td>图片无法显示时展示的文字</td></tr><tr><td><code>title</code></td><td>提示文本</td><td>鼠标悬停时显示的文字</td></tr><tr><td><code>width</code></td><td>设置图片宽度</td><td>值一般是数字</td></tr><tr><td><code>height</code></td><td>设置图片高度</td><td>值一般是数字</td></tr></tbody></table><p>注意，标签中存在多个属性时，属性之间用空格隔开，且没有先后顺序之分。</p><h3 id="_10-超链接" tabindex="-1"><a class="header-anchor" href="#_10-超链接" aria-hidden="true">#</a> 10. 超链接</h3><p>通过使用超链接，能够实现鼠标点击后跳转到其他页面的效果。</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>a</span> <span class="token attr-name">href</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>跳转页面地址<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>a</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>其中，<code>href</code> 是必需属性，用于指定跳转的页面地址，当 <code>href</code> 属性的值为 <code>#</code>，则表示该链接为空链接，点击后不会进行跳转。除此之外，<code>a</code> 标签还有 <code>target</code> 属性，用于指定是否在新窗口中打开跳转页面。当属性值为 <code>_blank</code> 时，表示在新窗口打开。默认情况下，表示在当前窗口打开。</p><h3 id="_11-音频" tabindex="-1"><a class="header-anchor" href="#_11-音频" aria-hidden="true">#</a> 11. 音频</h3><p>使用该标签往网页中添加音频，使用语法如下。</p><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>audio</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>音频地址<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>audio</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>常见属性如下表：</p><table><thead><tr><th>属性</th><th>作用</th><th>说明</th></tr></thead><tbody><tr><td><code>src</code></td><td>音频地址</td><td>必需属性，支持 <code>MP3</code>、<code>Wav</code></td></tr><tr><td><code>controls</code></td><td>是否显示音频控制面板</td><td></td></tr><tr><td><code>loop</code></td><td>是否循环播放</td><td></td></tr><tr><td><code>autoplay</code></td><td>是否自动播放</td><td></td></tr></tbody></table><h3 id="_12-视频" tabindex="-1"><a class="header-anchor" href="#_12-视频" aria-hidden="true">#</a> 12. 视频</h3><div class="language-html line-numbers-mode" data-ext="html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>video</span> <span class="token attr-name">src</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>视频地址<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>video</span><span class="token punctuation">&gt;</span></span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><table><thead><tr><th>属性</th><th>作用</th><th>说明</th></tr></thead><tbody><tr><td><code>src</code></td><td>视频地址</td><td>必需属性，支持 <code>MP4</code>、<code>WebM</code></td></tr><tr><td><code>controls</code></td><td>是否显示视频控制面板</td><td></td></tr><tr><td><code>loop</code></td><td>是否循环播放</td><td></td></tr><tr><td><code>muted</code></td><td>是否静音播放</td><td></td></tr><tr><td><code>autoplay</code></td><td>是否自动播放</td><td>必须在开启静音播放的前提下才能生效</td></tr></tbody></table><h3 id="_13-列表" tabindex="-1"><a class="header-anchor" href="#_13-列表" aria-hidden="true">#</a> 13. 列表</h3><h3 id="_14-表格" tabindex="-1"><a class="header-anchor" href="#_14-表格" aria-hidden="true">#</a> 14. 表格</h3><h3 id="_15-表单" tabindex="-1"><a class="header-anchor" href="#_15-表单" aria-hidden="true">#</a> 15. 表单</h3>`,73);function d(i,u){const a=s("Share");return t(),e("div",null,[o,p(a,{colorful:""})])}const h=n(l,[["render",d],["__file","20230829-html.html.vue"]]);export{h as default};
